const COMPONENT_TYPES = new Set(["rune"]);

export function quote(input: { items: Array<{ type: string }> }): { premium: number } {
  if (input.items.length === 0) return { premium: PROCESSING_FEE };

  const componentCounts: Record<string, number> = {};
  let base = 0;
  for (const item of input.items) {
    if (COMPONENT_TYPES.has(item.type)) {
      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
    } else {
      base += BASE_PREMIUMS[item.type];
    }
  }
  for (const [type, count] of Object.entries(componentCounts)) {
    base += count === 3 ? 60 : count * BASE_PREMIUMS[type];
  }

  return { premium: Math.ceil(base + base * FIRST_INSURANCE_RATE + PROCESSING_FEE) };
}
